<html>
    <head>
        <meta charset=\"UTF-8\">
        <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">
        <title>{% block title %}Welcome!{% endblock %}</title>

        <link rel=\"icon\" href=\"data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 128 128%22><text y=%221.2em%22 font-size=%2296%22>⚫️</text><text y=%221.3em%22 x=%220.2em%22 font-size=%2276%22 fill=%22%23fff%22>sf</text></svg>\">
        {% block stylesheets %}
        {% endblock %}

        {% block javascripts %}
            {% block importmap %}{{ importmap(\x27app\x27) }}{% endblock %}
        {% endblock %}

        {% set frankenphpHotReload = app.request.server.get(\x27FRANKENPHP_HOT_RELOAD\x27) %}
        {% if frankenphpHotReload %}
        <meta name=\"frankenphp-hot-reload:url\" content=\"{{ frankenphpHotReload }}\">
        <script src=\"https://cdn.jsdelivr.net/npm/idiomorph\"></script>
        <script src=\"https://cdn.jsdelivr.net/npm/frankenphp-hot-reload/+esm\" type=\"module\"></script>
        {% endif %}
        <link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.8/dist/css/bootstrap.min.css\" rel=\"stylesheet\">
    </head>
    <body class=\"d-flex flex-column min-vh-100\">
    <nav class=\"navbar navbar-expand-lg navbar-dark bg-dark\">
        <div class=\"container\">
            <a class=\"navbar-brand\" href=\"{{ path(\x27app_auto_index\x27) }}\">
                CRUD
            </a>
        </div>
    </nav>

    <main class=\"container my-4 flex-grow-1\">
        {% block body %}{% endblock %}
    </main>


    <footer class=\"bg-dark text-white text-center py-3\">
        Mateusz Borula © 2025
    </footer>

    <script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.3.8/dist/js/bootstrap.bundle.min.js\"></script>
    </body>
</html>
